77	
78	  // Item-specific modifiers
79	  it("quote with cursed sword adds 50% surcharge on item base premium (100 + 50 curse)", () => {
80	    expect(quote({ yearsWithMHPCO: 0 }, [
81	      { type: "sword", material: "steel", enchantment: 0, cursed: true }
82	    ])).toBe(170);
83	  });
84	  it("quote with sword at enchantment 5 adds 30% surcharge on item base premium", () => {
85	    expect(quote({ yearsWithMHPCO: 0 }, [
86	      { type: "sword", material: "steel", enchantment: 5, cursed: false }
87	    ])).toBe(148);
88	  });
89	  it("quote with sword at enchantment 4 does not add high-enchantment surcharge", () => {
90	    expect(quote({ yearsWithMHPCO: 0 }, [
91	      { type: "sword", material: "steel", enchantment: 4, cursed: false }
92	    ])).toBe(115);
93	  });
94	  it("quote with cursed sword at enchantment 5 stacks both surcharges", () => {
95	    expect(quote({ yearsWithMHPCO: 0 }, [
96	      { type: "sword", material: "steel", enchantment: 5, cursed: true }
97	    ])).toBe(203);
98	  });
99	
100	  // Modifier scope on multi-item policies
101	  it("quote with cursed sword + plain amulet applies curse only to sword's base premium (210 before policy modifiers and fee)", () => {
102	    expect(quote({ yearsWithMHPCO: 0 }, [
103	      { type: "sword", material: "steel", enchantment: 0, cursed: true },
104	      { type: "amulet", material: "silver", enchantment: 0, cursed: false }
105	    ])).toBe(236);
106	  });
107	
108	  // Policy-wide modifiers
109	  it("quote with customer at exactly 2 years applies 20% loyalty discount on policy total", () => {
110	    expect(quote({ yearsWithMHPCO: 2 }, [
111	      { type: "sword", material: "steel", enchantment: 0, cursed: false }
112	    ])).toBe(95);
113	  });
114	  it("quote with customer at less than 2 years does not apply loyalty discount", () => {
115	    expect(quote({ yearsWithMHPCO: 1 }, [
116	      { type: "sword", material: "steel", enchantment: 0, cursed: false }
117	    ])).toBe(115);
118	  });
119	  it("quote first insurance adds 10% surcharge per item on the policy", () => {
120	    expect(quote({ yearsWithMHPCO: 0 }, [
121	      { type: "sword", material: "steel", enchantment: 0, cursed: false },
122	      { type: "amulet", material: "silver", enchantment: 0, cursed: false }
123	    ])).toBe(181);
124	  });
125	  it.todo("quote follow-up contract (after first quote in scenario) applies 15% discount on policy total");
126	
127	  // Rounding
128	  it.todo("premium calculation yielding 197.5 rounds up to 198");
129	
130	  // Integration examples from spec
131	  it.todo("newcomer with cursed sword (steel, enchantment 3, 0 years) returns premium 165");
132	  it.todo("long-standing customer's second contract: cursed sword (enchantment 7, 3 years, 2nd quote) returns premium 160");
133	
134	  // Quote: error cases
135	  it.todo("quote with unknown item type causes CLI to exit non-zero with error to stderr");
136	
137	  // Claim: basic payouts
138	  it.todo("claim on regular sword (steel, enchantment 3) with damage 500 returns payout 400 (full reimbursement minus 100 deductible)");
139	  it.todo("claim on rune (insurance value 250) with damage 200 returns payout 100 (full reimbursement minus 100 deductible)");
140	
141	  // Claim: enchantment threshold
142	  it.todo("claim on steel sword enchantment 9 with damage 1000 returns payout 400 (50% reimbursement, then 100 deductible)");
143	
144	  // Claim: dragon material
145	  it.todo("claim on dragon-material sword enchantment 5 with damage 800 returns payout 700 (full reimbursement, then 100 deductible)");
146	  it.todo("claim on dragon-material sword enchantment 9 with damage 1000 returns payout 400 (50% rule wins, then deductible)");
147	  it.todo("claim on dragon-material sword enchantment 8 with damage 1000 returns payout 400 (high-enchantment clause applies, then deductible)");
148	
149	  // Claim: deductible per damage event
150	  it.todo("claim with two damaged items (sword 500 + amulet 300) applies deductible per item: payout 600");
151	
152	  // Claim: multiple items of the same type
153	  it.todo("policy covering two swords has insurance sum 2000 and cap 4000");
154	  it.todo("claim with two sword damages on a two-sword policy treats each as separate damage with own deductible");
155	  it.todo("claim with more sword damages than swords insured causes CLI to exit non-zero");
156	
157	  // Claim: cap
158	  it.todo("policy with sword + amulet has insurance sum 1600 and cap 3200");
159	  it.todo("policy with sword + 3 runes has insurance sum 1750 (block discount affects premium only, not cap)");
160	  it.todo("cap is based on unmodified insurance value (cursed sword cap = 2000)");
161	  it.todo("first claim of 1500 on sword (cap 2000) returns payout 1400 with remainingCap 600");
162	  it.todo("second claim of 1500 with remainingCap 600 returns payout 600 with remainingCap 0");
163	
164	  // Claim: rounding
165	  it.todo("payout calculation yielding 350.5 rounds down to 350");
166	
167	  // Claim: error cases
168	  it.todo("claim referencing item not in policy causes CLI to exit non-zero with error to stderr");
169	  it.todo("claim with negative damage amount causes CLI to exit non-zero with error to stderr");
170	
171	  // CLI integration
172	  it.todo("CLI reads scenario JSON from stdin and writes results JSON to stdout in step order");
173	});
