1	// claim-office.ts
2	
3	type Customer = { yearsWithMHPCO: number; previousContracts?: number };
4	type Item = {
5	  type: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
6	  material?: string;
7	  enchantment?: number;
8	  cursed?: boolean;
9	};
10	
11	const PROCESSING_FEE = 5;
12	const INSURANCE_SURCHARGE_RATE = 0.1;
13	const COMPONENT_BLOCK_SIZE = 3;
14	const COMPONENT_BLOCK_PRICE = 60;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
18	
19	const BASE_PREMIUMS: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	  rune: 25,
25	  moonstone: 25,
26	};
27	
28	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
29	
30	function surchargeRate(item: Item): number {
31	  const curseRate = item.cursed ? CURSE_SURCHARGE_RATE : 0;
32	  const highEnchantmentRate =
33	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
34	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
35	      : 0;
36	  return curseRate + highEnchantmentRate;
37	}
38	
39	function nonComponentItemPremium(item: Item): number {
40	  const base = BASE_PREMIUMS[item.type];
41	  return base * (1 + surchargeRate(item));
42	}
43	
44	function componentBasePremium(count: number, unitPrice: number): number {
45	  return count === COMPONENT_BLOCK_SIZE
46	    ? COMPONENT_BLOCK_PRICE
47	    : count * unitPrice;
48	}
49	
50	function itemsBasePremium(items: Item[]): number {
51	  const componentCounts: Record<string, number> = {};
52	  let nonComponentBase = 0;
53	  for (const item of items) {
54	    if (COMPONENT_TYPES.has(item.type)) {
55	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
56	    } else {
57	      nonComponentBase += nonComponentItemPremium(item);
58	    }
59	  }
60	  const componentBase = Object.entries(componentCounts).reduce(
61	    (total, [type, count]) =>
62	      total + componentBasePremium(count, BASE_PREMIUMS[type]),
63	    0
64	  );
65	  return nonComponentBase + componentBase;
66	}
67	
68	const LOYALTY_THRESHOLD_YEARS = 2;
69	const LOYALTY_DISCOUNT_RATE = 0.2;
70	
71	export function quote(customer: Customer, items: Item[]): number {
72	  const itemsBase = itemsBasePremium(items);
73	  const insuranceSurcharge = itemsBase * INSURANCE_SURCHARGE_RATE;
74	  const loyaltyDiscount =
75	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
76	      ? itemsBase * LOYALTY_DISCOUNT_RATE
77	      : 0;
78	  return Math.ceil(
79	    itemsBase + insuranceSurcharge - loyaltyDiscount + PROCESSING_FEE
80	  );
81	}
